<!DOCTYPE html><html lang="es"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"><title>Marketing - Reportes</title><link href="https://fonts.googleapis.com/icon?family=Material+Icons" rel="stylesheet"><link rel="stylesheet" href="../../assets/framework/framework.css"><script src="../../assets/framework/framework.js" defer></script><link rel="stylesheet" href="marketing_styles.css"></head><body><div class="layout"><?php require __DIR__ . '/../../partials/marketing_nav.php'; ?><main class="main"><header class="navbar"><div class="navbar-left"><button class="btn-icon" onclick="toggleSidebar()"><span class="material-icons">menu</span></button><div class="navbar-title">Reportes de marketing</div></div><?= renderBotonPerfil($perfil['avatar_path'] ?? ($_SESSION['avatar_path'] ?? null)) ?></header><section class="content page-stack"><?php if (($flash['message'] ?? '') !== ''): ?><div class="flash <?= mh($flash['type']) ?>"><?= mh($flash['message']) ?></div><?php endif; ?><form class="marketing-card" method="post"><input type="hidden" name="action" value="save_report"><h2>Crear reporte</h2><div class="form-grid"><select name="subscription_id" required><option value="">Suscripcion</option><?php foreach($suscripciones as $s): ?><option value="<?= (int)$s['id'] ?>"><?= mh(($s['user_label'] ?? '') . ' - ' . ($s['plan_name'] ?? '')) ?></option><?php endforeach; ?></select><input type="date" name="period_start" required><input type="date" name="period_end" required><input name="title" placeholder="Titulo" required><label><input type="checkbox" name="visible_to_client" value="1"> Visible para cliente</label></div><div class="form-grid" style="margin-top:12px"><textarea name="summary" placeholder="Resumen"></textarea><textarea name="conclusions" placeholder="Conclusiones"></textarea><textarea name="next_actions" placeholder="Proximas acciones"></textarea></div><button class="btn btn-aceptar" type="submit">Guardar reporte</button></form><div class="marketing-card"><h2>Reportes</h2><div class="report-list"><?php foreach($reportes as $r): ?><article><div class="plan-head"><h3><?= mh($r['title'] ?? '') ?></h3><span class="pill"><?= !empty($r['visible_to_client']) ? 'Visible' : 'Interno' ?></span></div><p class="muted"><?= mh($r['user_label'] ?? '') ?> · <?= dateLabel($r['period_start'] ?? '') ?> - <?= dateLabel($r['period_end'] ?? '') ?></p><p><?= nl2br(mh($r['summary'] ?? '')) ?></p></article><?php endforeach; ?><?php if(empty($reportes)): ?><div class="empty">No hay reportes.</div><?php endif; ?></div></div></section></main></div><?php $perfilObligatorio=false; require_once __DIR__ . '/../../partials/modal_perfil/modal_perfil.php'; ?></body></html>
